<script>
import http from "@/network/Base.js";
import { mapState } from "vuex";
import { SweetModal, SweetModalTab } from "sweet-modal-vue";
import GMap from "../../Tables/map/Map.vue";
export default {
  components: {
    // Detail
    GMap,
    SweetModal,
    SweetModalTab
  },
  data() {
    return {
      // show: false,
      drop: false,
      loading: false,
      failed: false,
      search: "",
      retry: () => {},
      retryData: "",
      selectedIndex: 0,
      tabdata: [],
      selectedName: "",
      opened: [],
      restrictions: [],
      editMode: false,
      noProgrammes: false,
      coverPrice: "",
      wrongAmount: "",
      payload: {},
      wrongAmountMessage: "",
      noSelectedProviders: "",
      noSelectedProvidersMessage: "",
      radio: "Basic",
      searchNames: [],
      displayValue: "none",
      contraintsExpanded: false,
      isChecked: true,
      providerPlans: {
        "Nyaho Medical Centre": {
          providerId: "1265432",
          plans: [{}]
        }
      },
      programmes: [],
      selectedProviders: [],
      checkboxes: {
        unchecked: false,
        checked: true,
        uncheckedDisabled: false,
        checkedDisabled: true
      },
      searchData: ["Nyaho Medical Centre"],
      name: "",
      selected: null
    };
  },
  methods: {
    removeComplaint(i) {
      this.search = "";
    },
    showPreventedAction() {
      this.$refs.modal_.open();
    },
    populateModal(index) {
      this.selectedProviders = this.programmes[index].providers;
      this.coverPrice = this.programmes[index].coverPerEmployee;
      this.selectedIndex = index;
      this.editMode = true;
      this.$refs.modal.open();
    },
    addProviderAndTerm(term) {
      this.selectedProviders.push({
        name: this.name,
        term: term,
        approved: false
      });
      this.name = "";
      this.$refs.nestedChild.close();
    },
    toggle(i) {
      this.drop = !this.drop;
      this.selectedIndex = i;
      const index = this.opened.indexOf(i);
      if (index > -1) {
        this.opened.splice(index, 1);
      } else {
        this.opened.push(i);
      }
    },
    closeModal() {
      this.selectedProviders = [];
      this.coverPrice = "";
      this.editMode = false;
      this.name = "";
      this.wrongAmount = "";
      this.wrongAmountMessage = "";
      this.noSelectedProviders = "";
      this.noSelectedProvidersMessage = "";
    },
    selectProvider(provider) {
      //this.selected = plan;
      if (!!provider) this.$refs.nestedChild.open();
    },
    selectPlan(plan) {
      //this.selected = plan;
      if (!!plan) this.$refs.nestedChild.open();
    },
    addProgramme(programme) {
      // handle network call here to create new programme.
      if (programme.coverPerEmployee && programme.numberOfProviders > 0) {
        this.failed = false;
        this.loading = true;
        this.noProgrammes = true;
        if (this.editMode) {
          // update
          this.programmes[this.selectedIndex] = programme;
        } else {
          // create new
          this.$store
            .dispatch("createProgramme", {
              companyId: this.sz_companyid,
              programme
            })
            .then(res => {
              const params_arr = [];
              res.data.results.forEach(el => {
                params_arr.push(el);
              });
              this.failed = false;
              this.loading = false;
              this.noProgrammes = false;
              this.programmes.push(programme);
            })
            .catch(e => {
              this.failed = true;
              this.loading = false;
              this.noProgrammes = true;
              this.$snotify.error("Could not create your programmes");
            });
        }
        this.$refs.modal.close();
        this.selectedProviders = [];
        this.coverPrice = "";
        this.editMode = false;
      }
      if (!programme.coverPerEmployee || programme.coverPerEmployee <= 0) {
        this.wrongAmount = "is-danger";
        this.wrongAmountMessage = "Please enter a valid amount";
      }
      if (programme.numberOfProviders <= 0) {
        this.noSelectedProviders = "is-danger";
        this.noSelectedProvidersMessage =
          "You need to select atleast 1 provider";
      }
    },
    fetchProgrammes() {
      this.failed = false;
      this.loading = true;
      this.noProgrammes = true;
      this.$store
        .dispatch("fetchProgrammes", this.sz_companyid)
        .then(res => {
          const params_arr = [];
          res.data.results.forEach(el => {
            params_arr.push(el);
          });
          this.failed = false;
          this.loading = false;
          this.noProgrammes = false;
        })
        .catch(e => {
          this.failed = true;
          this.loading = false;
          this.noProgrammes = true;
          this.retry = this.fetchProgrammes;
          this.$snotify.error("Could not fetch your programmes");
        });
    },
    nameSearch(i) {
      this.search = this.tableData[i].name;
    },
    toggleExpansion() {
      this.contraintsExpanded = !this.contraintsExpanded;
    }
  },
  watch: {
    coverPrice: function() {
      this.wrongAmount = "";
      this.wrongAmountMessage = "";
    },
    name: function() {
      this.noSelectedProviders = "";
      this.noSelectedProvidersMessage = "";
    }
  },
  computed: {
    filteredDataArray() {
      return this.searchData.filter(option => {
        return (
          option
            .toString()
            .toLowerCase()
            .indexOf(this.name.toLowerCase()) >= 0
        );
      });
    },
    ...mapState({
      sz_companyid: state => state.corporate.company_id
    }),
    tableData() {
      return this.details.filter(el => {
        let search = this.search.toLowerCase();
        if (
          el.healthPlan
            .toString()
            .toLowerCase()
            .search(search) > -1
        )
          return true;
        else return false;
      });
    }
  },
  created() {
    this.failed = false;
    this.loading = true;
    this.noProgrammes = true;
    this.$store
      .dispatch("fetchProgrammes", this.sz_companyid)
      .then(res => {
        const params_arr = [];
        res.data.results.forEach(el => {
          params_arr.push(el);
        });
        this.failed = false;
        this.loading = false;
        this.noProgrammes = false;
      })
      .catch(e => {
        this.failed = true;
        this.loading = false;
        this.noProgrammes = true;
        this.retry = this.fetchProgrammes;
        this.$snotify.error("Could not fetch your programmes");
      });
  }
};
</script>

